.liquid-tabs__content { margin-top: 18px; outline: none; }
.liquid-tabs__content:focus-visible { outline: 3px solid rgba(0,122,255,.28); outline-offset: 4px; border-radius: 12px; }

:is(.dark, [data-theme="dark"]) .liquid-tabs__list { --tabs-tint: rgba(72,72,78,.78); --tabs-active-tint: rgba(82,82,88,.52); --tabs-label: rgba(235,235,245,.66); --tabs-label-active: #fff; border-color: rgba(255,255,255,.16); background: rgba(235,235,245,.1); box-shadow: inset 0 1px 2px rgba(0,0,0,.32), 0 1px 0 rgba(255,255,255,.08); color: #f5f5f7; }
:is(.dark, [data-theme="dark"]) .liquid-tabs__indicator { box-shadow: 0 3px 9px rgba(0,0,0,.42), 0 .5px 0 rgba(255,255,255,.14); }
:is(.dark, [data-theme="dark"]) .liquid-tabs__indicator-lens { background: radial-gradient(ellipse at var(--liquid-light-x) 42%, rgba(255,255,255,.14), transparent 52%), rgba(255,255,255,.045); backdrop-filter: blur(10px) saturate(1.5) brightness(.94); -webkit-backdrop-filter: blur(10px) saturate(1.5) brightness(.94); box-shadow: inset 2px 0 2px rgba(80,190,255,.1), inset -2px 0 2px rgba(255,90,130,.07); }
:is(.dark, [data-theme="dark"]) .liquid-tabs__indicator-rim { border-color: rgba(255,255,255,.2); box-shadow: inset 1px 1px 1.5px rgba(255,255,255,.22), inset -1px -1px 1.5px rgba(0,0,0,.42); }
:is(.dark, [data-theme="dark"]) .liquid-tabs__list[data-interacting] .liquid-tabs__indicator { box-shadow: 0 9px 22px rgba(0,0,0,.46), inset 0 0 9px rgba(255,255,255,.2), 0 0 0 .5px rgba(255,255,255,.2); }

@media (prefers-reduced-motion: reduce) {
  .liquid-switch *, .liquid-slider *, .liquid-tabs * { transition-duration: .01ms !important; animation-duration: .01ms !important; }
}
